import type { Diagnostic } from '@codemirror/lint';
import type { RangeSet } from '@codemirror/state';
import { RangeSetBuilder } from '@codemirror/state';
import type { Decoration, EditorView } from '@codemirror/view';

import { errorMark } from '../decorations/decoration-marks.js';
import {
  pastingMode,
  usedErrors,
  type PastingInfo,
} from '../editor-state-configs/editor-config.js';
import type { FilterFieldErrorMessages } from '../types/filter-field-error.js';

const getRenderMessage = (message: string) => {
  const messageWrapperElement = document.createElement('div');
  messageWrapperElement.className = 'strato-filterfield-error-wrapper';
  messageWrapperElement.innerHTML = `<div class="strato-filterfield-error-icon-wrapper"><svg focusable="false"
  role="img"
  aria-hidden="true"
  fill="currentColor"
  width="16"
  height="16"
  xmlns="http://www.w3.org/2000/svg"
  viewBox="0 0 20 20"><path d="M9.2799 6.26743H10.7799V10.7674H9.2799V6.26743Z" />
  <path d="M11.0299 12.7674C11.0299 12.2151 10.5822 11.7674 10.0299 11.7674C9.47762 11.7674 9.0299 12.2151 9.0299 12.7674C9.0299 13.3197 9.47762 13.7674 10.0299 13.7674C10.5822 13.7674 11.0299 13.3197 11.0299 12.7674Z" />
  <path d="M10.737 1.54289C10.3465 1.15237 9.71332 1.15237 9.32279 1.54289L1.54289 9.32279C1.15237 9.71332 1.15237 10.3465 1.54289 10.737L9.32279 18.5169C9.71332 18.9074 10.3465 18.9074 10.737 18.5169L18.5169 10.737C18.9074 10.3465 18.9074 9.71332 18.5169 9.32279L10.737 1.54289ZM10.0299 2.95711L17.1027 10.0299L10.0299 17.1027L2.95711 10.0299L10.0299 2.95711Z" /></svg></div><div>${message}</div>`;
  return () => messageWrapperElement;
};

/** @internal */
export function generateErrorsOrDiagnostics(
  view: EditorView,
): RangeSet<Decoration>;
/** @internal */
export function generateErrorsOrDiagnostics(
  view: EditorView,
  messages?: FilterFieldErrorMessages,
): Diagnostic[];
/** @internal */
export function generateErrorsOrDiagnostics(
  view: EditorView,
  messages?: FilterFieldErrorMessages,
): RangeSet<Decoration> | Diagnostic[] {
  const builder = new RangeSetBuilder<Decoration>();
  const diagnostics: Diagnostic[] = [];
  const errorsStateField = view.state.field(usedErrors, false);
  const pastingStateField = view?.state.field(pastingMode, false);

  if (!errorsStateField || view.visibleRanges.length === 0) {
    if (messages !== undefined) {
      builder.finish();
      return diagnostics;
    }

    return builder.finish();
  }

  for (const error of errorsStateField.errors) {
    const {
      range: { from, to },
      decoration,
      message: errorMessage,
    } = error;
    let message;
    let messageDetails: string | string[] | undefined;

    if (typeof errorMessage === 'string') {
      message = errorMessage;
    } else {
      message = errorMessage.type;
      messageDetails = errorMessage.details;
    }

    if (from <= view.visibleRanges[0].to && to <= view.visibleRanges[0].to) {
      const showError = !isErrorInPastingRange(from, to, pastingStateField);

      if (showError) {
        builder.add(from, to, decoration ?? errorMark);
      }

      if (messages !== undefined) {
        let errorMessage = message;
        const errorType = messages[message as keyof FilterFieldErrorMessages];
        if (errorType) {
          if (typeof errorType === 'function') {
            // eslint-disable-next-line @typescript-eslint/no-explicit-any -- The correct details type is always paired with the matching error type at runtime.
            errorMessage = (errorType as (...args: any[]) => string)(
              messageDetails,
            );
          } else {
            errorMessage = errorType;
          }
        }

        if (showError) {
          diagnostics.push({
            from,
            to,
            severity: 'error',
            message: '',
            renderMessage: getRenderMessage(errorMessage),
          });
        }
      }
    }
  }

  if (messages !== undefined) {
    builder.finish();
    return diagnostics;
  }

  return builder.finish();
}

function isErrorInPastingRange(
  errorFrom: number,
  errorTo: number,
  pastingStateField: PastingInfo | undefined,
) {
  if (!pastingStateField?.range || !pastingStateField.pastingInProgress) {
    return false;
  }

  const pastingRangeFrom = pastingStateField.range.from;
  const pastingRangeTo = pastingStateField.range.to;

  return (
    // Check if error starts inside the pasting range
    // Check if error surrounds the pasting range
    (errorFrom >= pastingRangeFrom && errorFrom <= pastingRangeTo) ||
    // Check if error starts inside the pasting range
    (errorTo >= pastingRangeFrom && errorTo <= pastingRangeFrom) ||
    (errorFrom <= pastingRangeFrom && errorTo >= pastingRangeTo)
  );
}
